class Solution:
    def reverseBetween(self, head, left, right):
        vals = []
        node = head
        while node:
            vals.append(node.val)
            node = node.next
        i, j = left - 1, right - 1
        vals[i:j + 1] = vals[i:j + 1][::-1]
        out = None
        for v in reversed(vals):
            out = ListNode(v, out)
        return out

