    const dummy = new ListNode(0, head);
    let prev = dummy;
    for (let i = 0; i < left - 1; i++) {
        prev = prev.next;
    }
    let cur = prev.next;
    for (let i = 0; i < right - left; i++) {
        const nxt = cur.next;
        cur.next = nxt.next;
        nxt.next = prev.next;
        prev.next = nxt;
    }
    return dummy.next;
};
